// // This module implements a 4-bit ring counter that rotates its single '1' bit to the right on every positive clock edge.
module ring_counter (
    input clk,
    input reset,
    output reg [3:0] q
);

always @(posedge clk or negedge reset) begin
    if (~reset)
        q <= 4'b0001;
    else
        q <= {q[2:0], q[3]};
end

endmodule
